from typing import TypedDict, Literal
from langgraph.graph import StateGraph, END
from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser

llm = ChatOpenAI(model="claude-sonnet-5", temperature=0)
parser = StrOutputParser()

class RetryState(TypedDict):
    task: str
    attempt: int
    max_attempts: int
    last_output: str
    success: bool
    errors: list[str]

def execute_task(state: RetryState) -> RetryState:
    chain = (
        ChatPromptTemplate.from_template(
            "Extract a valid JSON object with keys 'name' and 'value' from: {task}\n"
            "Previous failures: {errors}\n"
            "Return ONLY the JSON object."
        ) | llm | parser
    )
    output = chain.invoke({"task": state["task"], "errors": str(state["errors"])})
    return {"last_output": output, "attempt": state["attempt"] + 1}

def validate_output(state: RetryState) -> RetryState:
    import json as _json
    try:
        parsed = _json.loads(state["last_output"])
        if "name" in parsed and "value" in parsed:
            return {"success": True}
    except _json.JSONDecodeError as e:
        pass
    return {
        "success": False,
        "errors": state["errors"] + [f"Attempt {state['attempt']}: invalid JSON — {state['last_output'][:50]}"],
    }

def should_retry(state: RetryState) -> Literal["execute_task", "__end__"]:
    if state["success"]:
        return END
    if state["attempt"] >= state["max_attempts"]:
        return END
    return "execute_task"

graph = StateGraph(RetryState)
graph.add_node("execute_task", execute_task)
graph.add_node("validate_output", validate_output)
graph.set_entry_point("execute_task")
graph.add_edge("execute_task", "validate_output")
graph.add_conditional_edges("validate_output", should_retry)

chain = graph.compile()
result = chain.invoke({
    "task": "Product: Widget X, Price: 49.99",
    "attempt": 0, "max_attempts": 3, "last_output": "",
    "success": False, "errors": [],
})
print(f"Success: {result['success']}, Attempts: {result['attempt']}")
print(result["last_output"])
